const express = require('express');
const session = require('express-session');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

app.use(helmet());
app.use(express.json());
app.use(express.urlencoded({ extended: false }));

const sessionStore = new Map();

app.use(session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 15 * 60 * 1000
  }
}));

const twilioAccountSid = process.env.TWILIO_ACCOUNT_SID;
const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN;
const twilioPhoneNumber = process.env.TWILIO_PHONE_NUMBER;

let twilioClient;
if (twilioAccountSid && twilioAuthToken) {
  const twilio = require('twilio');
  twilioClient = twilio(twilioAccountSid, twilioAuthToken);
}

const mfaStore = new Map();

const CODE_EXPIRY = 5 * 60 * 1000;
const MAX_ATTEMPTS = 3;
const LOCKOUT_DURATION = 15 * 60 * 1000;

const sendSmsLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
  message: { error: 'Too many SMS requests. Please try again later.' },
  standardHeaders: true,
  legacyHeaders: false
});

const verifyLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 10,
  message: { error: 'Too many verification attempts. Please try again later.' },
  standardHeaders: true,
  legacyHeaders: false
});

function generateSecureCode() {
  const randomBytes = crypto.randomBytes(4);
  const code = (randomInt(randomBytes) % 900000 + 100000).toString();
  return code;
}

function randomInt(buffer) {
  return buffer.readUInt32BE(0);
}

function validatePhoneNumber(phone) {
  if (!phone || typeof phone !== 'string') {
    return false;
  }
  
  const cleanPhone = phone.replace(/\D/g, '');
  
  if (cleanPhone.length < 10 || cleanPhone.length > 15) {
    return false;
  }
  
  const phoneRegex = /^\+?[1-9]\d{9,14}$/;
  return phoneRegex.test('+' + cleanPhone);
}

function sanitizePhoneNumber(phone) {
  const cleanPhone = phone.replace(/\D/g, '');
  return cleanPhone.startsWith('1') ? '+' + cleanPhone : '+1' + cleanPhone;
}

function hashCode(code, salt) {
  return crypto.pbkdf2Sync(code, salt, 10000, 64, 'sha512').toString('hex');
}

async function sendSMS(phoneNumber, code) {
  if (!twilioClient) {
    console.log(`[DEV MODE] SMS Code for ${phoneNumber}: ${code}`);
    return true;
  }
  
  try {
    await twilioClient.messages.create({
      body: `Your verification code is: ${code}. This code will expire in 5 minutes. Do not share this code with anyone.`,
      from: twilioPhoneNumber,
      to: phoneNumber
    });
    return true;
  } catch (error) {
    console.error('SMS sending failed:', error.message);
    return false;
  }
}

function cleanupExpiredCodes() {
  const now = Date.now();
  for (const [key, data] of mfaStore.entries()) {
    if (now > data.expiresAt) {
      mfaStore.delete(key);
    }
  }
}

setInterval(cleanupExpiredCodes, 60000);

app.post('/api/auth/send-code', sendSmsLimiter, async (req, res) => {
  try {
    const { phoneNumber, userId } = req.body;
    
    if (!userId || typeof userId !== 'string' || userId.length === 0 || userId.length > 100) {
      return res.status(400).json({ error: 'Invalid user identifier' });
    }
    
    if (!validatePhoneNumber(phoneNumber)) {
      return res.status(400).json({ error: 'Invalid phone number format' });
    }
    
    const sanitizedPhone = sanitizePhoneNumber(phoneNumber);
    const sessionKey = req.sessionID + ':' + userId;
    
    const existingData = mfaStore.get(sessionKey);
    if (existingData && existingData.lockedUntil && Date.now() < existingData.lockedUntil) {
      return res.status(429).json({ 
        error: 'Account temporarily locked due to too many failed attempts',
        retryAfter: Math.ceil((existingData.lockedUntil - Date.now()) / 1000)
      });
    }
    
    const code = generateSecureCode();
    const salt = crypto.randomBytes(16).toString('hex');
    const hashedCode = hashCode(code, salt);
    
    const mfaData = {
      hashedCode,
      salt,
      phoneNumber: sanitizedPhone,
      userId,
      createdAt: Date.now(),
      expiresAt: Date.now() + CODE_EXPIRY,
      attempts: 0,
      lockedUntil: null
    };
    
    mfaStore.set(sessionKey, mfaData);
    
    const smsSent = await sendSMS(sanitizedPhone, code);
    
    if (!smsSent) {
      mfaStore.delete(sessionKey);
      return res.status(500).json({ error: 'Failed to send verification code' });
    }
    
    req.session.mfaPending = true;
    req.session.userId = userId;
    
    res.json({ 
      success: true, 
      message: 'Verification code sent',
      expiresIn: CODE_EXPIRY / 1000
    });
    
  } catch (error) {
    console.error('Error in send-code:', error.message);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.post('/api/auth/verify-code', verifyLimiter, (req, res) => {
  try {
    const { code, userId } = req.body;
    
    if (!req.session.mfaPending) {
      return res.status(400).json({ error: 'No pending verification' });
    }
    
    if (!userId || typeof userId !== 'string' || userId !== req.session.userId) {
      return res.status(400).json({ error: 'Invalid request' });
    }
    
    if (!code || typeof code !== 'string') {
      return res.status(400).json({ error: 'Invalid verification code format' });
    }
    
    const cleanCode = code.replace(/\D/g, '');
    
    if (cleanCode.length !== 6) {
      return res.status(400).json({ error: 'Verification code must be 6 digits' });
    }
    
    const sessionKey = req.sessionID + ':' + userId;
    const mfaData = mfaStore.get(sessionKey);
    
    if (!mfaData) {
      return res.status(400).json({ error: 'No verification code found or code expired' });
    }
    
    if (mfaData.lockedUntil && Date.now() < mfaData.lockedUntil) {
      return res.status(429).json({ 
        error: 'Too many failed attempts. Please request a new code.',
        retryAfter: Math.ceil((mfaData.lockedUntil - Date.now()) / 1000)
      });
    }
    
    if (Date.now() > mfaData.expiresAt) {
      mfaStore.delete(sessionKey);
      return res.status(400).json({ error: 'Verification code expired' });
    }
    
    const hashedInput = hashCode(cleanCode, mfaData.salt);
    
    const isValid = crypto.timingSafeEqual(
      Buffer.from(hashedInput, 'hex'),
      Buffer.from(mfaData.hashedCode, 'hex')
    );
    
    if (!isValid) {
      mfaData.attempts += 1;
      
      if (mfaData.attempts >= MAX_ATTEMPTS) {
        mfaData.lockedUntil = Date.now() + LOCKOUT_DURATION;
        mfaStore.set(sessionKey, mfaData);
        return res.status(429).json({ 
          error: 'Too many failed attempts. Account locked temporarily.',
          retryAfter: LOCKOUT_DURATION / 1000
        });
      }
      
      mfaStore.set(sessionKey, mfaData);
      
      return res.status(400).json({ 
        error: 'Invalid verification code',
        attemptsRemaining: MAX_ATTEMPTS - mfaData.attempts
      });
    }
    
    mfaStore.delete(sessionKey);
    
    req.session.mfaVerified = true;
    req.session.mfaPending = false;
    req.session.verifiedAt = Date.now();
    
    res.json({ 
      success: true, 
      message: 'Verification successful',
      userId: mfaData.userId
    });
    
  } catch (error) {
    console.error('Error in verify-code:', error.message);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.get('/api/auth/status', (req, res) => {
  res.json({
    mfaPending: req.session.mfaPending || false,
    mfaVerified: req.session.mfaVerified || false,
    userId: req.session.userId || null
  });
});

app.post('/api/auth/logout', (req, res) => {
  const sessionKey = req.sessionID + ':' + req.session.userId;
  mfaStore.delete(sessionKey);
  
  req.session.destroy((err) => {
    if (err) {
      return res.status(500).json({ error: 'Logout failed' });
    }
    res.json({ success: true, message: 'Logged out successfully' });
  });
});

function requireMFA(req, res, next) {
  if (!req.session.mfaVerified) {
    return res.status(401).json({ error: 'MFA verification required' });
  }
  
  const verifiedAt = req.session.verifiedAt;
  const sessionAge = Date.now() - verifiedAt;
  
  if (sessionAge > 30 * 60 * 1000) {
    req.session.mfaVerified = false;
    return res.status(401).json({ error: 'Session expired. Please verify again.' });
  }
  
  next();
}

app.get('/api/protected/resource', requireMFA, (req, res) => {
  res.json({ 
    message: 'Access granted to protected resource',
    userId: req.session.userId
  });
});

